import numpy as np

def ncf_forward(
    user_id: int,
    item_id: int,
    U: np.ndarray,
    V: np.ndarray,
    layers: list[tuple[np.ndarray, np.ndarray]]
) -> float:
    e_u = U[user_id]
    e_i = V[item_id]
    x = np.concatenate([e_u, e_i])
    for idx, (W, b) in enumerate(layers):
        x = x @ W.T + b
        if idx < len(layers) - 1:
            x = np.maximum(0, x)  # ReLU
        else:
            x = 1.0 / (1.0 + np.exp(-x))  # sigmoid
    return float(x.squeeze())
